class Solution(object):
    def uniqueXorTriplets(self, nums):
        n = len(nums)
        if n == 1:
            # Only triplet is (0,0,0): nums[0]^nums[0]^nums[0] = nums[0]
            return 1
        if n == 2:
            # Possible: a^a^a=a, b^b^b=b, a^a^b=b, a^b^b=a -> {a, b}
            return 2
        # For n >= 3, we have a permutation of [1..n].
        # Using elements 1, 2, ..., n we can generate XOR of 3 elements.
        # Key insight: x^x^y = y and x^y^y = x, so single element values are achievable.
        # Also x^y^z can generate many values.
        # For n >= 3, all values in [0, 2^(floor(log2(n))+1) - 1] are achievable.
        # Find the smallest power of 2 greater than n.
        upper = 1
        while upper <= n:
            upper <<= 1
        return upper
